// CsrTrigger pre-scans an instruction buffer (typically the loadable
// executable segments of an ELF) for `csrw 0x7C0, *` instructions and
// records their PCs. At retire time the simulator queries lookup(pc) to
// decide whether to drain state and hand back to QEMU.
//
// Pure logic: no SystemC, no DMI bus. Decoupled from GPR access -- the
// caller resolves runtime-kind rs1 values via decode_csrrw_rs1.

#pragma once

#include "hybrid/insn_match.h"

#include <cstddef>
#include <cstdint>
#include <cstring>
#include <optional>
#include <span>
#include <unordered_map>

namespace hybrid
{

struct CsrTriggerHit
{
  hybrid_handoff_kind kind;
  uint32_t insn;
};

inline auto decode_csrrw_rs1(uint32_t insn) -> uint8_t
{
  return static_cast<uint8_t>((insn >> 15) & 0x1Fu);
}

class CsrTrigger
{
public:
  void scan_buffer(std::span<const uint8_t> code, uint64_t base_pc)
  {
    std::size_t i = 0;
    while (i + sizeof(uint16_t) <= code.size()) {
      uint16_t lo = 0;
      std::memcpy(&lo, code.data() + i, sizeof(lo));

      const bool is_32 = (lo & 0x3u) == 0x3u;
      if (is_32) {
        if (i + sizeof(uint32_t) > code.size()) break;
        uint32_t insn = 0;
        std::memcpy(&insn, code.data() + i, sizeof(insn));
        hybrid_handoff_kind kind = HYBRID_HANDOFF_NONE;
        if (hybrid_match_handoff_insn(insn, &kind)) {
          hits_.insert_or_assign(base_pc + i, CsrTriggerHit{kind, insn});
        }
        i += sizeof(uint32_t);
      } else {
        i += sizeof(uint16_t);
      }
    }
  }

  // PC-trigger mode: insert a synthetic hit without scanning. Used when the
  // orchestrator passes --hybrid-exit-pc on the CLI; in that case the binary
  // need not contain a magic csrwi, and `insn` is unused (HandoffController
  // decodes the insn only on the RUNTIME arm; PC mode only inserts EXIT).
  void add_pc_hit(uint64_t pc, hybrid_handoff_kind kind)
  {
    hits_.insert_or_assign(pc, CsrTriggerHit{kind, /*insn=*/0u});
  }

  auto lookup(uint64_t pc) const -> std::optional<CsrTriggerHit>
  {
    if (auto it = hits_.find(pc); it != hits_.end()) return it->second;
    return std::nullopt;
  }

  auto empty() const -> bool { return hits_.empty(); }

private:
  std::unordered_map<uint64_t, CsrTriggerHit> hits_;
};

}  // namespace hybrid

/* rt_c_v_csrs.c - Round-trip fixture: V scalar CSR survival.
 *
 * Exercises vxsat, vxrm, vcsr, vtype, vl, and vstart across the
 * QEMU1 -> vsim -> QEMU2 handoff.
 *
 * Phase 1 (QEMU1): drain marker only (no V instructions; plugin PC
 *   drain constraint).
 * Phase 2 (vsim):  configure known V CSR values, then drain.
 *   - vsetvli: vl=8, vtype=e32/m1/ta/ma (0xD0)
 *   - csrw vxsat=1, vxrm=2, vstart=3 (vstart last: vsetvli resets it to 0)
 * Phase 3 (QEMU2): read V CSRs via csrr and verify each expected value.
 *   mstatus.VS is restored by ResumeDriver so no extra csrs needed.
 *   vstart is read before any V instruction so it holds the restored value.
 *
 * vcsr[0] = vxsat, vcsr[2:1] = vxrm -> expected vcsr = (2<<1)|1 = 5.
 * vtype: vsew=e32=010 at bits[5:3], vta=1 at bit6, vma=1 at bit7 -> 0xD0.
 */
#include "runtime/rt_c_helpers.h"

#include <stdint.h>

int main(void)
{
  /* Phase 1 (QEMU1): no V instructions before the drain marker. */
  rt_phase_qemu1_drain();

  /* Phase 2 (vsim): set known V CSR values.
   * crt0.S already set mstatus.VS=non-Off so vsetvli doesn't trap.
   * vstart must be written last: vsetvli resets vstart to 0. */
  asm volatile(
    "li     a0, 8\n"
    "vsetvli t0, a0, e32, m1, ta, ma\n"  /* vl=8, vtype=0xD0 */
    "li     t1, 1\n"
    "csrw   vxsat, t1\n"
    "li     t1, 2\n"
    "csrw   vxrm,  t1\n"
    "li     t1, 3\n"
    "csrw   vstart, t1\n"
    ::: "t0", "t1", "a0", "memory");

  rt_phase_vsim_drain();

  /* Phase 3 (QEMU2): verify V CSRs survived the round-trip.
   * Read vstart first, before any V instruction resets it to 0. */
  uint64_t vstart_out, vxsat_out, vxrm_out, vcsr_out, vtype_out, vl_out;
  asm volatile(
    "csrr %0, vstart\n"
    "csrr %1, vxsat\n"
    "csrr %2, vxrm\n"
    "csrr %3, vcsr\n"
    "csrr %4, vtype\n"
    "csrr %5, vl\n"
    : "=r"(vstart_out), "=r"(vxsat_out), "=r"(vxrm_out),
      "=r"(vcsr_out),   "=r"(vtype_out), "=r"(vl_out));

  int ok = 1;
  if (vl_out     != 8u)    { rt_semihost_writes("FAIL vl\n");     ok = 0; }
  if (vxsat_out  != 1u)    { rt_semihost_writes("FAIL vxsat\n");  ok = 0; }
  if (vxrm_out   != 2u)    { rt_semihost_writes("FAIL vxrm\n");   ok = 0; }
  if (vcsr_out   != 5u)    { rt_semihost_writes("FAIL vcsr\n");   ok = 0; }
  if (vtype_out  != 0xD0u) { rt_semihost_writes("FAIL vtype\n");  ok = 0; }
  if (vstart_out != 3u)    { rt_semihost_writes("FAIL vstart\n"); ok = 0; }

  if (ok)
    rt_semihost_writes("rt_c_v_csrs: PASS\n");
  else
    rt_semihost_writes("rt_c_v_csrs: FAIL\n");
  return ok ? 0 : 1;
}

