22	
23	QEMU_PLUGIN_EXPORT int qemu_plugin_version = QEMU_PLUGIN_VERSION;
24	
25	typedef struct {
26	    struct qemu_plugin_register *gpr[32];
27	    struct qemu_plugin_register *fpr[32];
28	    struct qemu_plugin_register *pc;
29	
30	    // M-mode CSRs as exposed by QEMU's gdbstub csr feature.
31	    struct qemu_plugin_register *mstatus;
32	    struct qemu_plugin_register *mepc;
33	    struct qemu_plugin_register *mtvec;
34	    struct qemu_plugin_register *mcause;
35	    struct qemu_plugin_register *mtval;
36	    struct qemu_plugin_register *mscratch;
37	    struct qemu_plugin_register *medeleg;
38	    struct qemu_plugin_register *mideleg;
39	    struct qemu_plugin_register *mip;
40	    struct qemu_plugin_register *mie;
41	    struct qemu_plugin_register *mcycle;
42	    struct qemu_plugin_register *minstret;
43	    struct qemu_plugin_register *satp;
44	
45	    struct qemu_plugin_register *pmpcfg[HYBRID_PMP_CFG_NUM];
46	    struct qemu_plugin_register *pmpaddr[HYBRID_PMP_ADDR_NUM];
47	
48	    struct qemu_plugin_register *vstart;
49	    struct qemu_plugin_register *vxsat;
50	    struct qemu_plugin_register *vxrm;
51	    struct qemu_plugin_register *vcsr;
52	    struct qemu_plugin_register *vtype;
53	    struct qemu_plugin_register *vl;
54	    struct qemu_plugin_register *vlenb;
55	    struct qemu_plugin_register *vreg[32];
56	} VcpuRegs;
57	
58	static struct qemu_plugin_scoreboard *vcpu_state;
59	static char *outfile_path;
60	
61	// PC-trigger mode: when enter_pc_arg is non-zero (set via plugin arg
62	// `enter_pc=0x...`), the CSR-insn matcher is bypassed entirely and the
63	// drain callback is registered only for instructions whose vaddr equals
64	// enter_pc_arg. The kind reported on the drain is HYBRID_HANDOFF_ENTER
65	// (entry into vsim), matching CSR-mode `csrwi 0x7C0, 0` semantics.
66	static uint64_t enter_pc_arg;
67	static int pc_mode;
68	
69	static struct qemu_plugin_register *find_reg(GArray *regs, const char *name)
70	{
71	    for (guint i = 0; i < regs->len; i++) {
72	        qemu_plugin_reg_descriptor *rd =
73	            &g_array_index(regs, qemu_plugin_reg_descriptor, i);
74	        if (g_ascii_strcasecmp(rd->name, name) == 0) {
75	            return rd->handle;
76	        }
77	    }
78	    return NULL;
79	}
80	
81	// Lazily resolves register handles. The plugin's vcpu_init runs before
82	// QEMU has registered the dynamic gdb coprocessors (FPU, virtual, csr,
83	// vector), so qemu_plugin_get_registers() returns only the 33 core CPU
84	// regs at that moment. By the time the entry trigger fires, all dynamic
85	// features are registered and a fresh call returns the full list.
86	static void resolve_handles(VcpuRegs *v)
87	{
88	    g_autoptr(GArray) regs = qemu_plugin_get_registers();
89	    for (int i = 0; i < 32; i++) {
90	        v->gpr[i] = find_reg(regs, hybrid_gpr_names[i]);
91	        v->fpr[i] = find_reg(regs, hybrid_fpr_names[i]);
92	    }
93	    v->pc = find_reg(regs, "pc");
94	
95	    v->mstatus  = find_reg(regs, "mstatus");
96	    v->mepc     = find_reg(regs, "mepc");
97	    v->mtvec    = find_reg(regs, "mtvec");
98	    v->mcause   = find_reg(regs, "mcause");
99	    v->mtval    = find_reg(regs, "mtval");
100	    v->mscratch = find_reg(regs, "mscratch");
101	    v->medeleg  = find_reg(regs, "medeleg");
102	    v->mideleg  = find_reg(regs, "mideleg");
103	    v->mip      = find_reg(regs, "mip");
104	    v->mie      = find_reg(regs, "mie");
105	    v->mcycle   = find_reg(regs, "mcycle");
106	    v->minstret = find_reg(regs, "minstret");
107	    v->satp     = find_reg(regs, "satp");
108	
109	    char buf[16];
110	    for (int i = 0; i < HYBRID_PMP_CFG_NUM; i++) {
111	        g_snprintf(buf, sizeof(buf), "pmpcfg%d", i);
112	        v->pmpcfg[i] = find_reg(regs, buf);
113	    }
114	    for (int i = 0; i < HYBRID_PMP_ADDR_NUM; i++) {
115	        g_snprintf(buf, sizeof(buf), "pmpaddr%d", i);
116	        v->pmpaddr[i] = find_reg(regs, buf);
117	    }
118	
119	    v->vstart = find_reg(regs, "vstart");
120	    v->vxsat  = find_reg(regs, "vxsat");
121	    v->vxrm   = find_reg(regs, "vxrm");
122	    v->vcsr   = find_reg(regs, "vcsr");
123	    v->vtype  = find_reg(regs, "vtype");
124	    v->vl     = find_reg(regs, "vl");
125	    v->vlenb  = find_reg(regs, "vlenb");
126	    for (int i = 0; i < 32; i++) {
127	        g_snprintf(buf, sizeof(buf), "v%d", i);
128	        v->vreg[i] = find_reg(regs, buf);
129	    }
130	}
131	
132	static uint64_t read_reg64(struct qemu_plugin_register *h)
133	{
134	    if (!h) return 0;
135	    g_autoptr(GByteArray) buf = g_byte_array_new();
136	    int sz = qemu_plugin_read_register(h, buf);
137	    if (sz <= 0) return 0;
138	    uint64_t v = 0;
139	    memcpy(&v, buf->data, sz < 8 ? (size_t) sz : 8);
140	    return v;
141	}
142	
143	// Reads up to `dst_max` bytes from a register handle. Returns the byte
144	// count written (0 on failure or NULL handle). Used for vector regs whose
145	// width = vlenb bytes.
146	static size_t read_reg_bytes(struct qemu_plugin_register *h,
147	                             uint8_t *dst, size_t dst_max)
148	{
149	    if (!h || dst_max == 0) return 0;
150	    g_autoptr(GByteArray) buf = g_byte_array_new();
151	    int sz = qemu_plugin_read_register(h, buf);
152	    if (sz <= 0) return 0;
153	    size_t n = (size_t) sz < dst_max ? (size_t) sz : dst_max;
154	    memcpy(dst, buf->data, n);
155	    return n;
156	}
157	
158	// Atomic on POSIX: write to .tmp, fsync, rename.
159	static int write_state_atomic(const struct hybrid_state_v1 *s, const char *path)
160	{
161	    char tmp[PATH_MAX];
162	    g_snprintf(tmp, sizeof(tmp), "%s.tmp.%d", path, (int) getpid());
163	    int fd = open(tmp, O_WRONLY | O_CREAT | O_TRUNC, 0600);
164	    if (fd < 0) {
165	        perror("hybrid_handoff: open tmp");
166	        return -1;
167	    }
168	    ssize_t want = (ssize_t) sizeof(*s);
169	    ssize_t got = write(fd, s, sizeof(*s));
170	    if (got != want) {
171	        perror("hybrid_handoff: write");
172	        close(fd);
173	        unlink(tmp);
174	        return -1;
175	    }
176	    fsync(fd);
177	    close(fd);
178	    if (rename(tmp, path) != 0) {
179	        perror("hybrid_handoff: rename");
180	        unlink(tmp);
181	        return -1;
182	    }
183	    return 0;
184	}
185	
186	static void on_handoff(unsigned int vcpu_idx, void *udata)
187	{
188	    hybrid_handoff_kind kind = (hybrid_handoff_kind) (uintptr_t) udata;
189	    if (kind != HYBRID_HANDOFF_ENTER) return;
190	
191	    VcpuRegs *v = qemu_plugin_scoreboard_find(vcpu_state, vcpu_idx);
192	    resolve_handles(v);
193	    struct hybrid_state_v1 s = {0};
194	    s.magic   = HYBRID_STATE_MAGIC;
195	    s.version = HYBRID_STATE_VERSION;
196	    s.flags   = HYBRID_FLAG_RV64;
197	    s.hart_id = vcpu_idx;
198	    s.priv    = 3;
199	    s.pc      = read_reg64(v->pc);
200	    for (int i = 0; i < 32; i++) s.gpr[i] = read_reg64(v->gpr[i]);
201	
202	    // Floating-point: only set FP flag if at least one handle was bound,
203	    // i.e. QEMU advertised the FPU feature (D extension).
204	    int has_fp = 0;
205	    for (int i = 0; i < 32; i++) {
206	        s.fpr[i] = read_reg64(v->fpr[i]);
207	        if (v->fpr[i]) has_fp = 1;
208	    }
209	    if (has_fp) s.flags |= HYBRID_FLAG_FP;
210	
211	    s.mstatus  = read_reg64(v->mstatus);
212	    s.mepc     = read_reg64(v->mepc);
213	    s.mtvec    = read_reg64(v->mtvec);
214	    s.mcause   = read_reg64(v->mcause);
215	    s.mtval    = read_reg64(v->mtval);
216	    s.mscratch = read_reg64(v->mscratch);
217	    s.medeleg  = read_reg64(v->medeleg);
218	    s.mideleg  = read_reg64(v->mideleg);
219	    s.mip      = read_reg64(v->mip);
220	    s.mie      = read_reg64(v->mie);
221	    s.mcycle   = read_reg64(v->mcycle);
222	    s.minstret = read_reg64(v->minstret);
223	    s.satp     = read_reg64(v->satp);
224	
225	    for (int i = 0; i < HYBRID_PMP_CFG_NUM; i++)
226	        s.pmpcfg[i] = read_reg64(v->pmpcfg[i]);
227	    for (int i = 0; i < HYBRID_PMP_ADDR_NUM; i++)
228	        s.pmpaddr[i] = read_reg64(v->pmpaddr[i]);
229	
230	    // Vector: only set V flag if QEMU advertised the V extension. vlenb
231	    // bounds the per-register byte count copied into vreg[].
232	    s.vstart = read_reg64(v->vstart);
233	    s.vxsat  = read_reg64(v->vxsat);
234	    s.vxrm   = read_reg64(v->vxrm);
235	    s.vcsr   = read_reg64(v->vcsr);
236	    s.vtype  = read_reg64(v->vtype);
237	    s.vl     = read_reg64(v->vl);
238	    s.vlenb  = read_reg64(v->vlenb);
239	    if (v->vlenb && s.vlenb > 0) {
240	        s.flags |= HYBRID_FLAG_V;
241	        size_t bytes = s.vlenb < HYBRID_VLEN_BYTES_MAX
242	                     ? (size_t) s.vlenb
243	                     : (size_t) HYBRID_VLEN_BYTES_MAX;
244	        for (int i = 0; i < 32; i++)
245	            (void) read_reg_bytes(v->vreg[i],
246	                                  &s.vreg[(size_t) i * HYBRID_VLEN_BYTES_MAX],
247	                                  bytes);
248	    }
249	
250	    if (write_state_atomic(&s, outfile_path) != 0) {
251	        fprintf(stderr, "hybrid_handoff: failed to write state file\n");
252	        exit(2);
253	    }
254	    fprintf(stderr,
255	            "hybrid_handoff: drained state to %s (pc=%#" PRIx64 "), exiting\n",
256	            outfile_path, s.pc);
257	    exit(0);
258	}
259	
260	static void vcpu_tb_trans(qemu_plugin_id_t id, struct qemu_plugin_tb *tb)
261	{
262	    (void) id;
263	    size_t n = qemu_plugin_tb_n_insns(tb);
264	    for (size_t i = 0; i < n; i++) {
265	        struct qemu_plugin_insn *insn = qemu_plugin_tb_get_insn(tb, i);
266	
267	        if (pc_mode) {
268	            // PC-trigger mode: vaddr-only match, no insn-data inspection,
269	            // no size guard (a future fixture might park enter_pc on a
270	            // compressed insn).
271	            if (qemu_plugin_insn_vaddr(insn) != enter_pc_arg) continue;
272	            qemu_plugin_register_vcpu_insn_exec_cb(
273	                insn, on_handoff, QEMU_PLUGIN_CB_R_REGS,
274	                (void *) (uintptr_t) HYBRID_HANDOFF_ENTER);
275	            continue;
276	        }
277	
278	        // CSR-trigger mode (default).
279	        size_t sz = qemu_plugin_insn_size(insn);
280	        if (sz != 4) continue;
281	        uint32_t raw = 0;
282	        if (qemu_plugin_insn_data(insn, &raw, sizeof(raw)) != sizeof(raw))
283	            continue;
284	        hybrid_handoff_kind kind = HYBRID_HANDOFF_NONE;
285	        if (!hybrid_match_handoff_insn(raw, &kind)) continue;
286	        qemu_plugin_register_vcpu_insn_exec_cb(
287	            insn, on_handoff, QEMU_PLUGIN_CB_R_REGS,
288	            (void *) (uintptr_t) kind);
289	    }
290	}
291	
292	QEMU_PLUGIN_EXPORT int qemu_plugin_install(qemu_plugin_id_t id,
293	                                           const qemu_info_t *info,
294	                                           int argc, char **argv)
295	{
296	    (void) info;
297	    for (int i = 0; i < argc; i++) {
298	        g_auto(GStrv) tok = g_strsplit(argv[i], "=", 2);
299	        if (g_strcmp0(tok[0], "outfile") == 0 && tok[1]) {
300	            outfile_path = g_strdup(tok[1]);
301	        } else if (g_strcmp0(tok[0], "enter_pc") == 0 && tok[1]) {
302	            char *endp = NULL;
303	            unsigned long long v = g_ascii_strtoull(tok[1], &endp, 0);
304	            if (!endp || *endp != '\0') {
305	                fprintf(stderr, "hybrid_handoff: invalid enter_pc=%s\n",
306	                        tok[1]);
307	                return -1;
308	            }
309	            enter_pc_arg = (uint64_t) v;
310	            pc_mode = 1;
311	        } else {
312	            fprintf(stderr, "hybrid_handoff: unknown option: %s\n", argv[i]);
313	            return -1;
314	        }
315	    }
316	    if (!outfile_path) {
317	        fputs("hybrid_handoff: outfile=PATH is required\n", stderr);
